import{_ as i,o as e,c as a,a2 as n}from"./chunks/framework.BflysNKA.js";const g=JSON.parse('{"title":"Windows 平台安装 Node.js","description":"","frontmatter":{},"headers":[],"relativePath":"node/windows.md","filePath":"node/windows.md","lastUpdated":1778663407000}'),l={name:"node/windows.md"};function t(p,s,r,h,o,d){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="windows-平台安装-node-js" tabindex="-1">Windows 平台安装 Node.js <a class="header-anchor" href="#windows-平台安装-node-js" aria-label="Permalink to &quot;Windows 平台安装 Node.js&quot;">​</a></h1><p>Claude Code、Codex、Gemini CLI 等工具都依赖 Node.js 环境。推荐直接安装 LTS 版本。</p><p>完整 CLI 接入流程见 <a href="/beginner/windows">Windows 快速接入</a>。</p><p>本文里的 PowerShell 命令，统一放在 <strong>管理员身份运行</strong> 的 PowerShell 里执行更稳。这样安装 Node.js、Git 和后面的全局 CLI 时更少遇到权限不足。</p><p>安装 Node.js 的目标不是“多装一个软件”，而是让系统拥有 <code>node</code> 和 <code>npm</code> 两个命令。<code>node</code> 用来运行 JavaScript CLI，<code>npm</code> 用来下载和更新 Claude Code、Codex、Gemini CLI 等工具。</p><p>后面准备装的是下面这些工具时：</p><ul><li>Claude Code 的 npm 版本</li><li>Codex</li><li>Gemini CLI</li><li>OpenCode</li><li>其他 npm 全局安装的 AI CLI</li></ul><p>那 Node.js 基本都绕不过去。先把这一层装稳，后面很多“命令不存在”“npm 装不上”“版本太旧”的问题都会少很多。</p><h2 id="方法一-浏览器下载安装包-推荐" tabindex="-1">方法一：浏览器下载安装包（推荐） <a class="header-anchor" href="#方法一-浏览器下载安装包-推荐" aria-label="Permalink to &quot;方法一：浏览器下载安装包（推荐）&quot;">​</a></h2><p>浏览器下载安装时，国内用户可以按这个顺序选：</p><ol><li>Node.js 中文站：<a href="https://nodejs.cn/download" target="_blank" rel="noreferrer">https://nodejs.cn/download</a></li><li>Node.js 镜像归档：<a href="https://npmmirror.com/mirrors/node/" target="_blank" rel="noreferrer">https://npmmirror.com/mirrors/node/</a></li><li>Node.js 英文官网：<a href="https://nodejs.org/en/download" target="_blank" rel="noreferrer">https://nodejs.org/en/download</a></li></ol><p>第一次安装优先打开 Node.js 中文站。页面是中文，能直接看到 Windows 安装包、macOS 安装包和不同架构选项，新手不容易点错。</p><p>第一次最容易犹豫的是“应该选 Current 还是 LTS”。<br> 不是为了测试最新特性时，优先选 <strong>LTS</strong>。LTS 的意义不是“更旧”，而是生态兼容性通常更稳，后面装 CLI 时踩版本坑的概率更低。</p><p>Windows 常用选择：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Windows 安装包 (.msi) -&gt; 64 位</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>下载后双击安装，保持默认选项。安装完成后重新打开终端。</p><p>使用镜像归档时：</p><ul><li>打开最新的 LTS 版本目录</li><li>Windows 64 位电脑选择 <code>node-v版本号-x64.msi</code></li><li>下载后双击安装</li></ul><p>安装选项保持默认即可。看到 <code>Add to PATH</code> 时不要取消，它会把 <code>node</code> 和 <code>npm</code> 加进系统命令路径。</p><p><code>Add to PATH</code> 的作用，就是让你后面在 PowerShell 里直接输入：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>系统也能认得这两个命令。<br> 如果这一步被取消，软件可能已经装上了，但终端里还是会表现成“命令不存在”。</p><h2 id="方法二-包管理器安装" tabindex="-1">方法二：包管理器安装 <a class="header-anchor" href="#方法二-包管理器安装" aria-label="Permalink to &quot;方法二：包管理器安装&quot;">​</a></h2><h3 id="使用-winget" tabindex="-1">使用 Winget <a class="header-anchor" href="#使用-winget" aria-label="Permalink to &quot;使用 Winget&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">winget install OpenJS.NodeJS.LTS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="使用-chocolatey" tabindex="-1">使用 Chocolatey <a class="header-anchor" href="#使用-chocolatey" aria-label="Permalink to &quot;使用 Chocolatey&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">choco install nodejs</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">lts</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="使用-scoop" tabindex="-1">使用 Scoop <a class="header-anchor" href="#使用-scoop" aria-label="Permalink to &quot;使用 Scoop&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">scoop install nodejs</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">lts</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="安装-git" tabindex="-1">安装 Git <a class="header-anchor" href="#安装-git" aria-label="Permalink to &quot;安装 Git&quot;">​</a></h2><p>Claude Code、Codex 处理代码仓库时经常会调用 Git。建议在安装 CLI 工具前先装好 Git。</p><p>Git 装好后，这些工具才能更准确地读取仓库状态、查看改动、生成 diff，也能在 Windows 上提供 Git Bash 这个更接近 Linux 的终端环境。</p><p>安装方式建议按这个顺序选：</p><ol><li>直接用 <code>winget</code></li><li>Git for Windows 官方站</li><li>Git 官网下载页</li></ol><p>不想手动找安装包，或者浏览器下载慢时，优先直接用 <code>winget</code>：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">winget install </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">id Git.Git </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">e </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">source winget</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>浏览器下载入口：</p><ul><li>Git 官网：<a href="https://git-scm.com/download/win" target="_blank" rel="noreferrer">https://git-scm.com/download/win</a></li><li>Git for Windows：<a href="https://gitforwindows.org/" target="_blank" rel="noreferrer">https://gitforwindows.org/</a></li></ul><p>下载慢时，可以使用可信的软件管家或镜像源里的 Git for Windows 安装包。安装后能正常输出 <code>git --version</code> 即可继续。</p><p>安装时保持默认选项。安装完成后，开始菜单里会多出 <strong>Git Bash</strong>，适合运行需要类 Linux shell 的工具。</p><p>只看“能不能装 CLI”时，很容易觉得 Git 可有可无。<br> 但只要你后面要让 Claude Code、Codex 这类工具处理真实项目，Git 基本就是它们理解当前仓库状态的基础设施之一。</p><h2 id="验证安装" tabindex="-1">验证安装 <a class="header-anchor" href="#验证安装" aria-label="Permalink to &quot;验证安装&quot;">​</a></h2><p>验证不是走流程，而是确认命令已经写入 PATH。只有下面三条都能输出版本号，后续工具安装才不会因为“命令不存在”中断。</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">git </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>能正常输出版本号就说明环境好了。</p><p>想再确认得彻底一点，可以顺手看：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> node</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> npm</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>只要这些命令都能定位到实际路径，后面大多数 CLI 安装问题就不会再停留在“环境根本没装好”这一层。</p><p>建议再配置 npm 镜像源。它可以加快 npm 下载速度，减少安装 CLI 时卡在依赖下载的情况：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config set registry https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">registry.npmmirror.com</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config get registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>第二行输出 <code>https://registry.npmmirror.com/</code> 就生效了。</p><h2 id="终端怎么选" tabindex="-1">终端怎么选 <a class="header-anchor" href="#终端怎么选" aria-label="Permalink to &quot;终端怎么选&quot;">​</a></h2><ul><li><strong>PowerShell</strong>：Windows 默认终端，适合复制本文里的 PowerShell 命令。</li><li><strong>CMD</strong>：兼容旧命令，日常配置优先使用 PowerShell。</li><li><strong>Git Bash</strong>：安装 Git 后自带，更适合运行 Claude Code 这类会调用 shell 的工具。</li></ul><p>优先用 PowerShell。遇到 Claude Code 执行 shell 命令异常时，再改用 Git Bash 或 WSL。</p><p>后面在 PowerShell 里遇到：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>running scripts is disabled on this system</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>那通常不是 Node.js 没装好，而是 PowerShell 执行策略还没放开。<br> 这种情况直接回 <a href="/beginner/windows">Windows 快速接入</a> 处理执行策略，再继续往下装 CLI 会更顺。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示-不是内部或外部命令" tabindex="-1">提示“不是内部或外部命令” <a class="header-anchor" href="#提示-不是内部或外部命令" aria-label="Permalink to &quot;提示“不是内部或外部命令”&quot;">​</a></h3><p>这是环境变量没生效。先关掉当前终端，再重新打开；还不行就重启电脑。</p><p>还不行就检查：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> node</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> npm</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>查不到路径，说明安装目录没有写进 PATH。重新安装 Node.js 或 Git，并保留默认 PATH 选项。</p><h3 id="安装失败" tabindex="-1">安装失败 <a class="header-anchor" href="#安装失败" aria-label="Permalink to &quot;安装失败&quot;">​</a></h3><p>先检查：</p><ul><li>是否被杀毒软件拦截</li><li>是否没有管理员权限</li><li>是否下载了错误的安装包架构</li></ul><p>Node.js、Cherry Studio、Claude Code 等新工具主要面向 Windows 10/11。旧系统遇到兼容问题时，建议升级系统或改用受支持环境。</p><h3 id="npm-安装很慢" tabindex="-1">npm 安装很慢 <a class="header-anchor" href="#npm-安装很慢" aria-label="Permalink to &quot;npm 安装很慢&quot;">​</a></h3><p>先确认镜像源：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config get registry</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不是 <code>https://registry.npmmirror.com/</code> 时重新设置：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">npm config set registry https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">registry.npmmirror.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果公司网络拦截 HTTPS，可以换手机热点确认是否为网络策略问题。</p><h3 id="明明装过了-版本却不是刚装的那个" tabindex="-1">明明装过了，版本却不是刚装的那个 <a class="header-anchor" href="#明明装过了-版本却不是刚装的那个" aria-label="Permalink to &quot;明明装过了，版本却不是刚装的那个&quot;">​</a></h3><p>这通常说明你机器里可能已经有旧版 Node.js，当前终端读到的是旧路径。</p><p>优先检查：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> node</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">node </span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">v</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果 <code>where node</code> 显示了多个路径，就先弄清当前到底在用哪一个，再决定是保留一个版本，还是清理旧版本。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/deploy/claude-code">Claude Code 部署</a></li><li><a href="/deploy/codex">Codex 部署</a></li><li><a href="/deploy/gemini-cli">Gemini CLI 部署</a></li></ul>`,80)])])}const k=i(l,[["render",t]]);export{g as __pageData,k as default};
